mapper.update:
update article_reports
set status = #{report.status},
    moderator_id = #{report.moderatorId},
    moderator_note = #{report.moderatorNote},
    resolved_at = #{report.resolvedAt}
where id = #{report.id}

mapper.select:
select id, article_id, reporter_id, reason, reporter_comment,
       status, moderator_id, moderator_note, created_at, resolved_at
from article_reports
where article_id = #{articleId}
  and reporter_id = #{reporterId}
  and status = 'PENDING'
